import React from 'react';
import { withStyles, withTheme } from '@material-ui/core/styles';
import ExpansionPanel from '@material-ui/core/ExpansionPanel';
import ExpansionPanelDetails from '@material-ui/core/ExpansionPanelDetails';
import ExpansionPanelSummary from '@material-ui/core/ExpansionPanelSummary';
import ExpandMoreIcon from '@material-ui/icons/ExpandMore';
import FormGroup from '@material-ui/core/FormGroup';

import SelectionControl from './SelectionControl';
import { CHECKBUKHARI,
  CHECKMUSLIM,
  CHECKTIRMIDZI,
  CHECKABUDAUD,
  CHECKNASAI,
  CHECKIBNUMAJAH,
  CHECKDARIMI,
  CHECKAHMAD,
  CHECKMALIK,
  CHECKDARUQUTHNI,
  CHECKIBNUKHUZAIMAH,
  CHECKIBNUHIBBAN,
  CHECKALMUSTADRAK,
  CHECKSYAFII,
  CHECKALL } from '../../store/action';

const styles = theme => ({
  root: {
    width: '100%',
  },
  summarySet: {
    padding: '0 8px 0 8px',
    height: 48,
    '&$expanded': {
      minHeight: 48,
    },
  },
  expanded: {},
  padRight: {
    '& > :last-child': {
      paddingRight: 0,
    },
  },
  detailSet: {
    flexDirection: 'column',
    padding: '0 0 8px 11px',
  },
});

class ControlledExpansionPanels extends React.Component {
  state = {
    expanded: 'panel1',
  };

  shouldComponentUpdate(nextProps, nextState) {
    if (this.props.theme.palette.type !== nextProps.theme.palette.type) {
      return true;
    }
    if (this.state.expanded !== nextState.expanded) {
      return true;
    }
    return false;
  }

  handleChange = panel => (event, expanded) => {
    if (event.target.innerText === 'Semua' || event.target.value === 'CHECKALL' || +event.target.innerText) {
      // if checkbox or label got clicked do not expand the panel
      return;
    };
    this.setState({
      expanded: expanded ? panel : false,
    });
  };

  render() {
    const { classes } = this.props;
    const { expanded } = this.state;

    const selectionControls = [
      {label: 'Shahih Bukhari', action: CHECKBUKHARI},
      {label: 'Shahih Muslim', action: CHECKMUSLIM},
      {label: 'Sunan Tirmidzi', action: CHECKTIRMIDZI},
      {label: 'Sunan Abu Daud', action: CHECKABUDAUD},
      {label: "Sunan Nasa'i", action: CHECKNASAI},
      {label: 'Sunan Ibn Majah', action: CHECKIBNUMAJAH},
      {label: 'Sunan Darimi', action: CHECKDARIMI},
      {label: 'Musnad Ahmad', action: CHECKAHMAD},
      {label: "Muwatha' Malik", action: CHECKMALIK},
      {label: 'Sunan Daruquthni', action: CHECKDARUQUTHNI},
      {label: 'Shahih Ibn Khuzaimah', action: CHECKIBNUKHUZAIMAH},
      {label: 'Shahih Ibn Hibban', action: CHECKIBNUHIBBAN},
      {label: 'Al Mustadrak', action: CHECKALMUSTADRAK},
      {label: "Musnad Syafi'i", action: CHECKSYAFII}
    ].map((obj, idx) => <SelectionControl key={idx + 1} elementid={idx + 1} label={obj.label} action={obj.action} />)

    return (
      <div className={classes.root}>
        <ExpansionPanel square elevation={0} expanded={expanded === 'panel1'} onChange={this.handleChange('panel1')}>
          <ExpansionPanelSummary
            expandIcon={<ExpandMoreIcon />}
            classes={{
              root: classes.summarySet,
              content: classes.padRight,
              expanded: classes.expanded
            }}
          >
            <SelectionControl key={0} elementid={0} label='Semua' action={CHECKALL} />
          </ExpansionPanelSummary>
          <ExpansionPanelDetails classes={{ root: classes.detailSet }}>
            <FormGroup>
              {selectionControls}
            </FormGroup>
          </ExpansionPanelDetails>
        </ExpansionPanel>
      </div>
    );
  }
}

export default withStyles(styles)(withTheme(ControlledExpansionPanels));
